#!/bin/bash\nffmpeg -f concat -safe 0 -i /Users/quantum/Desktop/ATLAS_CONTROL_SYSTEM/ltxv2_with_dialogue.txt -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2,fps=30,drawtext=fontfile=/System/Library/Fonts/Helvetica.ttc:text='Eleanor\\: This is it. Blackwood Estate.':fontcolor=white:fontsize=32:x=(w-text_w)/2:y=h-150:box=1:boxcolor=black@0.7:boxborderw=10:enable='between(t,8,14)',drawtext=fontfile=/System/Library/Fonts/Helvetica.ttc:text='Eleanor\\: Hello? I\\'m Eleanor Vance. I have an appointment.':fontcolor=white:fontsize=32:x=(w-text_w)/2:y=h-200:box=1:boxcolor=black@0.7:boxborderw=10:enable='between(t,41,49)',drawtext=fontfile=/System/Library/Fonts/Helvetica.ttc:text='Gatekeeper\\: You\\'re expected. But not welcome.':fontcolor=white:fontsize=32:x=(w-text_w)/2:y=h-200:box=1:boxcolor=black@0.7:boxborderw=10:enable='between(t,55,60)',drawtext=fontfile=/System/Library/Fonts/Helvetica.ttc:text='Eleanor\\: I... I have the letter. From the estate.':fontcolor=white:fontsize=32:x=(w-text_w)/2:y=h-200:box=1:boxcolor=black@0.7:boxborderw=10:enable='between(t,74,79)',drawtext=fontfile=/System/Library/Fonts/Helvetica.ttc:text='Gatekeeper\\: The house chooses who enters. Not I.':fontcolor=white:fontsize=32:x=(w-text_w)/2:y=h-200:box=1:boxcolor=black@0.7:boxborderw=10:enable='between(t,91,99)',drawtext=fontfile=/System/Library/Fonts/Helvetica.ttc:text='Eleanor\\: I didn\\'t come this far to turn back now.':fontcolor=white:fontsize=32:x=(w-text_w)/2:y=h-150:box=1:boxcolor=black@0.7:boxborderw=10:enable='between(t,110,114)',drawtext=fontfile=/System/Library/Fonts/Helvetica.ttc:text='Gatekeeper\\: Enter then. But remember... you were warned.':fontcolor=white:fontsize=32:x=(w-text_w)/2:y=h-200:box=1:boxcolor=black@0.7:boxborderw=10:enable='between(t,122,128)'" -c:v libx264 -pix_fmt yuv420p -y /Users/quantum/Desktop/atlas_output/ELEANOR_GATE_LTXV2_WITH_DIALOGUE.mp4\n